import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

// Behavior under test (from src/parseQuery.js):
//   - pairs are separated by "&"; empty segments are skipped
//   - a key seen once maps to its string value; seen multiple times maps to
//     an array of its values, in order of appearance
//   - a bare key (no "=") maps to ""
//   - "+" becomes a space in both keys and values, then each is
//     percent-decoded via decodeURIComponent
//   - if percent-decoding fails, the raw token (after "+" replacement) is
//     used as-is; the function never throws
//   - a single leading "?" is stripped

describe("parseQuery", () => {
  describe("basic parsing", () => {
    it("parses a single key/value pair", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("parses multiple distinct pairs", () => {
      expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
    });

    it("returns values as strings, not numbers", () => {
      const result = parseQuery("n=42");
      expect(result.n).toBe("42");
      expect(typeof result.n).toBe("string");
    });

    it("returns a plain object", () => {
      expect(parseQuery("a=1")).toBeInstanceOf(Object);
      expect(typeof parseQuery("")).toBe("object");
    });

    it("preserves key insertion order", () => {
      expect(Object.keys(parseQuery("z=1&a=2&m=3"))).toEqual(["z", "a", "m"]);
    });
  });

  describe("empty and edge inputs", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns an empty object for a lone '?'", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("returns an empty object for a string of only separators", () => {
      expect(parseQuery("&&&")).toEqual({});
    });
  });

  describe("leading '?' handling", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("works identically with or without the leading '?'", () => {
      expect(parseQuery("?a=1&b=2")).toEqual(parseQuery("a=1&b=2"));
    });

    it("strips only the first '?' — a second one is part of the key", () => {
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("does not strip a '?' that is not at the start", () => {
      expect(parseQuery("a=1?b=2")).toEqual({ a: "1?b=2" });
    });
  });

  describe("empty segments", () => {
    it("skips empty segments between pairs", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips leading and trailing separators", () => {
      expect(parseQuery("&a=1&")).toEqual({ a: "1" });
    });

    it("skips runs of consecutive separators", () => {
      expect(parseQuery("a=1&&&&b=2")).toEqual({ a: "1", b: "2" });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("handles multiple bare keys", () => {
      expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
    });

    it("mixes bare keys with valued keys", () => {
      expect(parseQuery("a=1&flag&b=2")).toEqual({ a: "1", flag: "", b: "2" });
    });
  });

  describe("empty keys and values", () => {
    it("maps a key with a trailing '=' to an empty string value", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });

    it("allows an empty key with a value", () => {
      expect(parseQuery("=v")).toEqual({ "": "v" });
    });

    it("allows a bare '=' as an empty key mapped to an empty value", () => {
      expect(parseQuery("=")).toEqual({ "": "" });
    });
  });

  describe("'=' inside values", () => {
    it("splits only on the first '=' and keeps the rest in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("preserves a leading '=' in the value", () => {
      expect(parseQuery("a==b")).toEqual({ a: "=b" });
    });

    it("keeps an equation-like value intact", () => {
      expect(parseQuery("eq=1=1")).toEqual({ eq: "1=1" });
    });
  });

  describe("repeated keys", () => {
    it("collects two occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("collects three or more occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2&a=3&a=4")).toEqual({
        a: ["1", "2", "3", "4"],
      });
    });

    it("preserves duplicate values in a repeated key", () => {
      expect(parseQuery("a=1&a=1")).toEqual({ a: ["1", "1"] });
    });

    it("keeps repeated and single keys independent", () => {
      expect(parseQuery("a=1&b=2&a=3")).toEqual({ a: ["1", "3"], b: "2" });
    });

    it("treats a repeated bare key as an array of empty strings", () => {
      expect(parseQuery("a&a")).toEqual({ a: ["", ""] });
    });

    it("combines a bare occurrence and a valued occurrence into an array", () => {
      expect(parseQuery("a&a=2")).toEqual({ a: ["", "2"] });
    });

    it("combines a valued occurrence followed by a bare one into an array", () => {
      expect(parseQuery("a=1&a")).toEqual({ a: ["1", ""] });
    });

    it("does not produce an array for a single occurrence", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
      expect(Array.isArray(parseQuery("a=1").a)).toBe(false);
    });
  });

  describe("'+' decoding to space", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=hello+world")).toEqual({ a: "hello world" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("first+name=John")).toEqual({ "first name": "John" });
    });

    it("decodes multiple and adjacent '+' characters", () => {
      expect(parseQuery("a=x++y")).toEqual({ a: "x  y" });
    });
  });

  describe("percent-decoding", () => {
    it("percent-decodes an encoded space in a value", () => {
      expect(parseQuery("a=hello%20world")).toEqual({ a: "hello world" });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("a%20b=1")).toEqual({ "a b": "1" });
    });

    it("decodes an encoded '&' so it is not treated as a separator", () => {
      expect(parseQuery("a=1%262")).toEqual({ a: "1&2" });
    });

    it("decodes an encoded '=' inside a value", () => {
      expect(parseQuery("a=1%3D1")).toEqual({ a: "1=1" });
    });

    it("decodes '%2B' to a literal '+'", () => {
      expect(parseQuery("a=%2B")).toEqual({ a: "+" });
    });

    it("decodes multi-byte UTF-8 sequences", () => {
      expect(parseQuery("check=%E2%9C%93")).toEqual({ check: "✓" });
    });

    it("applies '+' replacement before percent-decoding", () => {
      // "1+2%263" -> "1 2%263" -> "1 2&3"
      expect(parseQuery("a=1+2%263")).toEqual({ a: "1 2&3" });
    });
  });

  describe("malformed percent-encoding (never throws)", () => {
    it("uses the raw token when a value fails to decode", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("uses the raw token when a key fails to decode", () => {
      expect(parseQuery("%=v")).toEqual({ "%": "v" });
    });

    it("uses the raw token (after '+' replacement) on failure", () => {
      expect(parseQuery("a=%GG+x")).toEqual({ a: "%GG x" });
    });

    it("does not throw for an incomplete escape", () => {
      expect(() => parseQuery("a=%2")).not.toThrow();
      expect(parseQuery("a=%2")).toEqual({ a: "%2" });
    });

    it("decodes valid pairs even when another segment is malformed", () => {
      expect(parseQuery("good=%20&bad=%ZZ")).toEqual({
        good: " ",
        bad: "%ZZ",
      });
    });

    it("never throws across a batch of malformed inputs", () => {
      for (const qs of ["%", "%%", "a=%", "a=%1&b=%G", "%C3", "=%", "%&%"]) {
        expect(() => parseQuery(qs)).not.toThrow();
      }
    });
  });

  describe("combined and realistic inputs", () => {
    it("handles a mixed, realistic query string", () => {
      expect(
        parseQuery("?name=John+Doe&age=30&tag=a&tag=b&flag&empty="),
      ).toEqual({
        name: "John Doe",
        age: "30",
        tag: ["a", "b"],
        flag: "",
        empty: "",
      });
    });

    it("round-trips values produced by URLSearchParams", () => {
      const params = new URLSearchParams();
      params.append("q", "a b&c=d");
      params.append("q", "second");
      params.append("plus", "1+1");
      const result = parseQuery(params.toString());
      expect(result.q).toEqual(["a b&c=d", "second"]);
      expect(result.plus).toBe("1+1");
    });
  });

  describe("purity", () => {
    it("does not mutate or share state across calls", () => {
      const first = parseQuery("a=1&a=2");
      const second = parseQuery("a=3");
      expect(first).toEqual({ a: ["1", "2"] });
      expect(second).toEqual({ a: "3" });
    });
  });
});

